const pageRenderers = {home:homePage,network:networkPage,profiles:profilesPage,organizations:organizationsPage,opportunities:opportunitiesPage,messages:messagesPage,premium:premiumPage,account:accountPage};

const render = (request, locale, route, slug = "", env = {}) => {
  const tr = i18n[locale];
  const core = coreI18n[locale];
  const account = accountI18n[locale];
  const authFlow = authFlowI18n[locale];
  const feed = feedI18n[locale];
  const network = networkI18n[locale];
  const messages = messageI18n[locale];
  const url = new URL(request.url);
  const activeRoute = route === "profile" ? "profiles" : route;
  const routePath = route === "home" ? "" : route === "profile" ? `/profiles/${slug}` : `/${route}`;
  const alternates = localeOrder.map(code => `<link rel="alternate" hreflang="${code}" href="${url.origin}/${code}${routePath}">`).join("");
  const nav = tr.nav.map((label,index) => `<a class="${activeRoute === navRoutes[index] ? "active" : ""}" href="${href(locale,navRoutes[index])}">${label}</a>`).join("");
  const main = route === "profile" ? profileDetailPage(locale,tr,slug) : pageRenderers[route](locale,tr);
  const pageTitle = route === "profile" ? (profilesData.find(([name]) => slugifyProfile(name) === slug)?.[0] || slug) : route === "premium" ? core.premiumTitle : route === "account" ? account.accountTitle : tr.nav[navRoutes.indexOf(route)];
  const publicConfig = JSON.stringify({supabaseUrl:env.NEXT_PUBLIC_SUPABASE_URL || "",anonKey:env.NEXT_PUBLIC_SUPABASE_ANON_KEY || ""}).replace(/</g,"\\u003c");
  const pageConfig = JSON.stringify({locale,route,slug,account,authFlow,feed,network,messages,clubs:{...clubDirectoryBase,...clubDirectoryI18n[locale]},recruitment:{...recruitmentBase,...recruitmentI18n[locale]},directory:{...directoryV2Base,...directoryV2I18n[locale]},profileEditor:{...profileEditorBase,...profileEditorI18n[locale]},roles:tr.roles,roleCodes:["player","head_coach","assistant_coach","fitness_coach","sports_doctor","physiotherapist","osteopath","video_analyst","scout","agent","club_president","general_manager","marketing_manager","logistics_manager","administrative_manager"],open:tr.open,coreVerified:core.verified}).replace(/</g,"\\u003c");
  return `<!doctype html><html lang="${locale}" dir="${tr.dir}"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Football Network · ${pageTitle}</title><meta name="description" content="${tr.mission}"><link rel="canonical" href="${url.origin}/${locale}${routePath}">${alternates}<link rel="alternate" hreflang="x-default" href="${url.origin}/en${routePath}"><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Noto+Sans+Arabic:wght@400;500;600;700&display=swap" rel="stylesheet"><style>${css}${coreCss}${profileEditorCss}${directoryV2Css}${recruitmentCss}${clubDirectoryCss}</style></head><body><div class="shell"><header class="network-topbar"><a class="brand-lockup" href="${href(locale)}"><span class="brand-mark">FN</span><span>Football Network</span></a><div class="global-search"><input placeholder="${tr.search}" aria-label="${tr.search}"></div><nav class="top-nav">${nav}</nav><div class="top-actions">${languageSelect(locale,routePath)}${notificationCenter(locale,tr)}<a class="account-trigger" href="/${locale}/account" data-user-link>${tr.you}</a></div></header><div class="layout-frame">${leftRail(locale,tr)}<main class="center-scroll"><div class="app-status"><strong>Football Network</strong><span>${tr.bridge}</span></div>${main}</main>${rightRail(locale,tr)}</div></div><script>window.__FN_CONFIG__=${publicConfig};window.__FN_PAGE__=${pageConfig};${clientJs}${profileEditorClientJs}${directoryV2ClientJs}${recruitmentClientJs}${clubDirectoryClientJs}</script></body></html>`;
};

const detectLocale = request => {
  const header = request.headers.get("accept-language") || "";
  const candidates = header.split(",").map(item => item.split(";")[0].trim().toLowerCase().split("-")[0]);
  return candidates.find(code => localeOrder.includes(code)) || "fr";
};

export default {
  async fetch(request, env = {}) {
    const url = new URL(request.url);
    const parts = url.pathname.split("/").filter(Boolean);
    const legacyRoutes = {players:"profiles",clubs:"organizations",opportunities:"opportunities",messages:"messages"};
    if (!parts.length) return Response.redirect(new URL(`/${detectLocale(request)}`,url),302);
    if (!localeOrder.includes(parts[0])) {
      const route = legacyRoutes[parts[0]] || "";
      return Response.redirect(new URL(`/${detectLocale(request)}${route ? `/${route}` : ""}`,url),302);
    }
    const locale = parts[0];
    if (parts[1] === "profiles" && parts[2]) {
      return new Response(render(request,locale,"profile",parts[2],env),{headers:{"content-type":"text/html; charset=utf-8","cache-control":"public, max-age=60"}});
    }
    const requested = legacyRoutes[parts[1]] || parts[1] || "home";
    const route = [...routeNames,"premium","account"].includes(requested) ? requested : "home";
    return new Response(render(request,locale,route,"",env),{headers:{"content-type":"text/html; charset=utf-8","cache-control":"public, max-age=60"}});
  }
};
